<script>
(function() {
    const hub = document.getElementById('zzz-watch-hub-v2');
    if (!hub || hub.dataset.initialized) return;
    hub.dataset.initialized = 'true';

    const navButtons = hub.querySelectorAll('.nav-button');
    const pages = hub.querySelectorAll('.hub-page');
    navButtons.forEach(button => {
        button.addEventListener('click', () => {
            const targetPageId = button.dataset.page;
            navButtons.forEach(btn => btn.classList.remove('active'));
            button.classList.add('active');
            pages.forEach(page => {
                page.classList.toggle('active', page.dataset.section === targetPageId);
            });
        });
    });

    const sendAction = (message) => {
        if (!message || typeof message !== 'string' || !message.trim()) return;
        if (typeof triggerSlash === 'function') {
            triggerSlash(`/send ${message.trim()}|/trigger`);
        } else {
            console.log('Action Sent (Dev):', message.trim());
        }
    };

    hub.addEventListener('click', (event) => {
        const actionElement = event.target.closest('[data-action]');
        if (actionElement) {
            const action = actionElement.dataset.action;
            if (action) sendAction(action);
        }
    });

    const connectionElem = hub.querySelector('.connection-status-zzz');
    if (connectionElem) {
        if (connectionElem.textContent.includes('Kết nối bình thường')) {
            connectionElem.classList.add('connected');
        } else {
            connectionElem.classList.add('disconnected');
        }
    }
})();
</script>

</body>
</html>
